import styles from '../../styles/styles';

function AdminDashboard({ userData, onLogout }) {
  return (
    <div style={styles.dashboard}>
      <h1>Admin Dashboard</h1>
      <p>{userData.email}</p>
      <button onClick={onLogout}>Logout</button>
    </div>
  );
}

export default AdminDashboard;
